"""
Rolling window classes for streaming operations.

This module provides the base classes for rolling window operations that work
with both classic PySpark and Spark Connect.
"""

__all__ = ["RollingWindow"]


class RollingWindow:
    """
    Utility functions and classes for defining rolling windows in streaming DataFrames.

    Rolling window operations compute aggregations over time-based windows that slide
    relative to a frontier (currently only ProcessingTime is supported).

    Two types of windows are supported:
    - **Bounded windows**: Use `.over(RollingWindow.preceding(...))` to aggregate over
      a fixed time range (e.g., last 10 seconds). Data outside the window expires.
    - **Lifetime windows**: Pass aggregations without `.over()` to accumulate all
      historical data since stream start. Data never expires.

    .. versionadded:: 4.2.0

    Examples
    --------
    >>> from pyspark.sql import functions as F
    >>> from pyspark.sql.streaming.rolling_window import RollingWindow
    >>>
    >>> # Create a rolling window specification
    >>> frontier = RollingWindow.FrontierSpec(delay="0 seconds", alias="frontier")
    >>> window_spec = RollingWindow.preceding(RollingWindow.Range("10 seconds"))
    >>>
    >>> # Apply bounded rolling window aggregation (last 10 seconds)
    >>> df.rollingWindow(
    ...     partitionBy=["user_id"],
    ...     orderBy="event_time",
    ...     frontierSpec=frontier,
    ...     measures=[F.sum("value").over(window_spec)]
    ... )  # doctest: +SKIP
    >>>
    >>> # Apply lifetime window aggregation (all historical data)
    >>> df.rollingWindow(
    ...     partitionBy=["user_id"],
    ...     orderBy="event_time",
    ...     frontierSpec=frontier,
    ...     measures=[F.sum("value")]  # No .over() = lifetime window
    ... )  # doctest: +SKIP
    """

    class FrontierSpec:
        """
        Specification for the frontier in a rolling window operation.

        The frontier determines how the rolling window advances in time. Currently,
        only ProcessingTime mode is supported.

        .. versionadded:: 4.2.0

        Parameters
        ----------
        delay : str, optional
            The delay for frontier advancement as a string (e.g., "0 seconds", "10 seconds").
            Defaults to "0 seconds".
        alias : str, optional
            The alias for the frontier column in the output. Defaults to "__frontier".

        Examples
        --------
        >>> from pyspark.sql.streaming.rolling_window import RollingWindow
        >>>
        >>> # Create default frontier spec (no delay, alias "__frontier")
        >>> spec = RollingWindow.FrontierSpec()
        >>>
        >>> # Create frontier spec with 10 second delay
        >>> spec = RollingWindow.FrontierSpec(delay="10 seconds")
        >>>
        >>> # Create frontier spec with custom alias
        >>> spec = RollingWindow.FrontierSpec(delay="5 seconds", alias="processing_time")
        """

        def __init__(self, delay: str = "0 seconds", alias: str = "__frontier"):
            if type(delay) != str or len(delay.strip()) == 0:
                raise PySparkValueError(
                    errorClass="VALUE_NOT_NON_EMPTY_STR",
                    messageParameters={"arg_name": "delay", "arg_value": str(delay)},
                )
            if type(alias) != str or len(alias.strip()) == 0:
                raise PySparkValueError(
                    errorClass="VALUE_NOT_NON_EMPTY_STR",
                    messageParameters={"arg_name": "alias", "arg_value": str(delay)},
                )
            self._delay = delay.strip()
            self._alias = alias.strip()

        @property
        def delay(self) -> str:
            """The delay for frontier advancement."""
            return self._delay

        @property
        def alias(self) -> str:
            """The alias for the frontier column in the output."""
            return self._alias

    class Range:
        """
        Represents a time-based range for rolling window operations.

        .. versionadded:: 4.2.0

        Parameters
        ----------
        duration : str
            The duration for the range as a string (e.g., "10 seconds", "5 minutes").

        Examples
        --------
        >>> from pyspark.sql.streaming.rolling_window import RollingWindow
        >>>
        >>> range_spec = RollingWindow.Range("10 seconds")
        >>> range_spec = RollingWindow.Range("5 minutes")
        """

        def __init__(self, duration: str):
            if type(duration) != str or len(duration.strip()) == 0:
                raise PySparkValueError(
                    errorClass="VALUE_NOT_NON_EMPTY_STR",
                    messageParameters={"arg_name": "alias", "arg_value": str(delay)},
                )
            self._duration = duration.strip()

        @property
        def duration(self) -> str:
            """The duration for the range."""
            return self._duration

    @staticmethod
    def preceding(range: "RollingWindow.Range") -> "RollingWindow.RollingWindowRangeSpec":
        """
        Creates a window specification that includes data from the specified range
        before the frontier.

        For example, `preceding(Range("10 seconds"))` creates a window that spans from
        `(frontier - 10 seconds)` to `frontier`. This is useful for computing aggregations
        over historical data relative to the current frontier position.

        For lifetime windows that accumulate all historical data without expiration,
        simply pass the aggregation without `.over()` to the rollingWindow method.

        .. versionadded:: 4.2.0

        Parameters
        ----------
        range : RollingWindow.Range
            The range before the frontier to include.

        Returns
        -------
        :class:`RollingWindowRangeSpec`
            A rolling window specification that can be used with Column.over().

        Examples
        --------
        >>> from pyspark.sql import functions as F
        >>> from pyspark.sql.streaming.rolling_window import RollingWindow
        >>>
        >>> # Bounded rolling window (last 10 seconds)
        >>> window_spec = RollingWindow.preceding(RollingWindow.Range("10 seconds"))
        >>> measure = F.sum("value").over(window_spec)
        >>>
        >>> # Lifetime window (accumulates all historical data) - no .over() needed
        >>> measure = F.sum("value")
        """
        return RollingWindow.RollingWindowRangeSpec(range._duration)

    class RollingWindowRangeSpec:
        """
        A window specification for rolling window operations in streaming queries.

        This class defines the window boundaries relative to the frontier for rolling window
        aggregations. Unlike regular WindowSpec, this is specifically designed for streaming
        rolling windows with time-based ranges relative to a moving frontier.

        Instances of this class can only be created via [[RollingWindow.preceding]] factory method.

        For lifetime windows that accumulate all historical data, simply pass the aggregation
        without `.over()` to the rollingWindow method.

        .. versionadded:: 4.2.0

        Parameters
        ----------
        preceding_range : str
            The duration before the frontier to include (e.g., "10 seconds").
        """

        def __init__(self, preceding_range: str):
            if type(preceding_range) != str or len(preceding_range.strip()) == 0:
                raise PySparkValueError(
                    errorClass="VALUE_NOT_NON_EMPTY_STR",
                    messageParameters={"arg_name": "alias", "arg_value": str(delay)},
                )
            self._preceding_range = preceding_range.strip()

        @property
        def preceding_range(self) -> str:
            """The duration before the frontier to include."""
            return self._preceding_range
